def _sort_palette(self, sort_palette):
    """
    Reorders this image's palette using one of the predefined
    ``sort_palette`` keys accepted by :py:meth:`~PIL.Image.Image.quantize`.

    :param sort_palette: ``"luminance"`` or ``"rgb"``.
    :returns: A new image with a reordered palette.
    """
    source_palette = self.im.getpalette("RGB")[:768]
    colors = [
        tuple(source_palette[i : i + 3]) for i in range(0, len(source_palette), 3)
    ]

    if sort_palette == "luminance":
        def sort_key(index):
            r, g, b = colors[index]
            return 0.299 * r + 0.587 * g + 0.114 * b

    elif sort_palette == "rgb":
        def sort_key(index):
            return colors[index]

    else:
        raise ValueError(
            "sort_palette must be None, 'luminance' or 'rgb', "
            f"not {sort_palette!r}"
        )

    dest_map = sorted(range(len(colors)), key=sort_key)
    return self.remap_palette(dest_map, bytes(source_palette))

